import{_ as a,o as t,c as r,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"11. Overtime In Lieu","description":"","frontmatter":{"title":"11. Overtime In Lieu","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","overtime"]},"headers":[],"relativePath":"ebas/has-managers-admin/managers-admin/hours-of-work/11-overtime-in-lieu.md","filePath":"ebas/has-managers-admin/managers-admin/hours-of-work/11-overtime-in-lieu.md"}'),i={name:"ebas/has-managers-admin/managers-admin/hours-of-work/11-overtime-in-lieu.md"};function n(s,e,m,l,h,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="_11-overtime-in-lieu" tabindex="-1">11. Overtime In Lieu <a class="header-anchor" href="#_11-overtime-in-lieu" aria-label="Permalink to &quot;11. Overtime In Lieu&quot;">​</a></h1><p><strong>11.1</strong> An Employee may elect, with the consent of the Employer, to take time off in lieu of payment for overtime at a time or times agreed with the Employer.</p><p><strong>11.2</strong> Overtime taken as time off during ordinary time hours will be taken at the penalty time rate. That is, one and one half hours off or two hours off, as the case may be, for each overtime hour worked.</p><p><strong>11.3</strong> An Employer will provide payment at the appropriate overtime rate where time off in lieu has not been taken within four weeks of accrual.</p><p><strong>11.4</strong> For the purposes of this clause, in accruing or calculating payment of overtime, each period of overtime will stand alone.</p><p>PART E – EDUCATION AND PROFESSIONAL DEVELOPMENT</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',7)])])}const f=a(i,[["render",n]]);export{d as __pageData,f as default};
